SELECT * FROM OrderTicket WHERE WorkOrderId = 402869;
SELECT * FROM T009_CUSTOMER_ORDERS WHERE C009_ORDER_ID = (SELECT SalesOrderID FROM OrderTicket WHERE WorkOrderId = 402869);
SELECT * FROM T010_CUSTOMER_ORDER_DETAILS WHERE C010_ORDER_ID = (SELECT SalesOrderID FROM OrderTicket WHERE WorkOrderId = 402869);
SELECT * FROM T009_WORK_ORDERS WHERE C009_ORDER_ID = 402869;
SELECT * FROM Common_PreAlert WHERE WorkOrderNum LIKE '%-402869';
SELECT * FROM RenaissanceDW.dbo.DailyCustomerOrderMetrics WHERE work_order_id = 402869;
SELECT * FROM T005_WAREHOUSES WHERE C005_WAREHOUSE_NAME LIKE '%Telus%';
SELECT * FROM T064_PICKING_LOCATIONS WHERE C064_WHID IN (SELECT C005_WAREHOUSE_ID FROM T005_WAREHOUSES WHERE C005_WAREHOUSE_NAME LIKE '%Telus%');
SELECT TOP 2000 C009_TOTAL_COST, C009_WORK_ORDER_NO, C009_WAREHOUSE_ID, C009_PICK_LOC_ID FROM T009_WORK_ORDERS WHERE C009_TARGET_PRODUCT_ID = (SELECT C002_PRODUCT_ID FROM T002_PRODUCTS WHERE C002_PRODUCT_SKU = '800-45484-05' AND C002_ACTIVE = 1 AND C002_VISIBLE = 1) AND C009_CUSTOM_FIELD1 != '014' ORDER BY C009_ORDER_ID DESC;